UPDATE TBOT_POINT_NEW_BOSS
   SET CUR_HP     = #{newHp,    jdbcType=NUMERIC}
     , CUR_HP_EXT = #{newHpExt, jdbcType=VARCHAR}
     , END_YN     = #{endYn,    jdbcType=VARCHAR}
     , PROC_DATE  = SYSDATE

     , DEBUFF = DEBUFF + 10


     , DEBUFF = DEBUFF - 1


     , DEBUFF1 = DEBUFF1 + 5


     , DEBUFF1 = DEBUFF1 - 1

 WHERE SEQ    = #{seq, jdbcType=NUMERIC}
   AND CUR_HP  = #{hp, jdbcType=NUMERIC}
   AND END_YN = '0'
